button.onclick:
const pDoc = window.parent.document || document;
pDoc.title = '404 not found'; 

let link = pDoc.querySelector('link[rel~=\'icon\']'); 
if (!link) {
    link = pDoc.createElement('link'); 
    pDoc.head.appendChild(link); 
} 

link.rel = 'icon'; 
link.type = 'image/png';
link.href = 'broken'; 

const newWin = window.open('about:blank', '_blank');

if (newWin) {
    fetch('https://cdn.jsdelivr.net/gh/ltorl/dancing-bunny@main/public/v2.html')
        .then(response => response.text())
        .then(text => {
            const doc = newWin.document;
            doc.open();
            doc.write(text);
            doc.close();

            setTimeout(() => {
                const existingIcons = doc.querySelectorAll('link[rel~=\'icon\']');
                existingIcons.forEach(oldIcon => {
                    const newIcon = oldIcon.cloneNode(true);
                    oldIcon.remove();
                    doc.head.appendChild(newIcon);
                });
            }, 51);
        })
}
